  async function loadAppUsers() {
    const tbody = qs('#tabla-usuarios-body');
    if (!tbody) return;
    tbody.innerHTML = '<tr><td colspan="7" class="empty">Cargando…</td></tr>';
    try {
      const [rows, tecnicos] = await Promise.all([
        fetchJson(API + '/app-users'),
        fetchJson(API + '/tecnicos').catch(() => []),
      ]);
      const list = toArray(rows);
      appUsersCache = list;
      const tecList = toArray(tecnicos);
      const me = getSessionUser();
      const activeAdmins = list.filter(function (u) {
        return u.role === 'admin' && (u.activo === 1 || u.activo === true);
      }).length;
      if (!list.length) {
        tbody.innerHTML = '<tr><td colspan="7" class="empty">No hay usuarios registrados.</td></tr>';
        renderUsuariosAccessEditor([]);
        loadAppDeletedUsers();
        loadReportSchedules();
        return;
      }
      tbody.innerHTML = list
        .map(function (r) {
          const id = r.id;
          const activo = !!(r.activo === 1 || r.activo === true);
          const isSelf = me && Number(me.id) === Number(id);
          const rowIsActiveAdmin = r.role === 'admin' && activo;
          const blockLastAdmin = rowIsActiveAdmin && activeAdmins <= 1;
          const canDelete = !isSelf && !blockLastAdmin;
          let delTitle = 'Eliminar cuenta del sistema';
          if (isSelf) delTitle = 'No puedes eliminar tu propia cuenta';
          else if (blockLastAdmin) delTitle = 'No se puede eliminar el único administrador activo';
          return (
            '<tr data-user-row="' +
            id +
            '"><td>' +
            escapeHtml(r.username) +
            '</td><td class="usuarios-td-nombre"><div class="usuarios-nombre-cell"><span class="usuarios-display-label">' +
            escapeHtml(r.display_name || '—') +
            '</span><span class="usuarios-nombre-actions"><button type="button" class="btn small outline usuarios-edit-display-btn" data-user-id="' +
            id +
            '" title="Editar nombre completo"><i class="fas fa-user-edit" aria-hidden="true"></i><span class="visually-hidden"> Editar nombre</span></button></span></div></td><td>' +
            renderUsuariosRoleSelect(id, r.role || 'invitado') +
            '</td><td>' +
            renderUsuariosTecnicoSelect(id, tecList, r.tecnico_id) +
            '</td><td><input type="checkbox" class="usuarios-activo-check" id="usuarios-act-' +
            id +
            '" data-user-id="' +
            id +
            '" title="Cuenta activa" ' +
            (activo ? 'checked' : '') +
            '></td><td class="muted">' +
            escapeHtml(r.creado_en || '—') +
            '</td><td><button type="button" class="btn small danger usuarios-delete-btn" data-user-id="' +
            id +
            '" title="' +
            escapeHtml(delTitle) +
            '" ' +
            (canDelete ? '' : 'disabled') +
            '><i class="fas fa-user-minus"></i></button></td></tr>'
          );
        })
        .join('');
      renderUsuariosAccessEditor(list);
    } catch (e) {
      appUsersCache = [];
      tbody.innerHTML =
        '<tr><td colspan="7" class="empty">' + escapeHtml(parseApiError(e) || 'No se pudo cargar usuarios.') + '</td></tr>';
      renderUsuariosAccessEditor([]);
    }
    loadAppDeletedUsers();
    loadReportSchedules();
  }

  function renderUsuariosAccessEditor(users) {
    const sel = qs('#usuarios-perm-user');
    const tabsWrap = qs('#usuarios-perm-tabs-wrap');
    const colsWrap = qs('#usuarios-perm-columns-wrap');
    if (!sel || !tabsWrap || !colsWrap) return;
    const list = toArray(users || []);
    if (!list.length) {
      sel.innerHTML = '<option value="">Sin usuarios</option>';
      tabsWrap.innerHTML = '<p class="hint">Sin datos</p>';
      colsWrap.innerHTML = '<p class="hint">Sin datos</p>';
      accessEditorState = { userId: null, tabPermissions: {}, columnPermissions: {} };
      return;
    }
    const selectedId = accessEditorState.userId != null ? Number(accessEditorState.userId) : Number(list[0].id);
    sel.innerHTML = list
      .map((u) => `<option value="${escapeHtml(String(u.id))}" ${Number(u.id) === selectedId ? 'selected' : ''}>${escapeHtml(u.username)} (${escapeHtml(u.role)})</option>`)
      .join('');
    const row = list.find((u) => Number(u.id) === Number(sel.value)) || list[0];
    accessEditorState.userId = Number(row.id);
    accessEditorState.tabPermissions = parseUserAccessObject(row.tab_permissions || row.tabPermissions);
    accessEditorState.columnPermissions = parseUserAccessObject(row.column_permissions || row.columnPermissions);

    tabsWrap.innerHTML = ACCESS_TAB_DEFS.map(([id, label]) => {
      const checked = accessEditorState.tabPermissions[id] !== false;
      return `<label style="display:flex;align-items:center;gap:0.45rem;"><input type="checkbox" class="usuarios-perm-tab-check" data-tab-id="${escapeHtml(id)}" ${checked ? 'checked' : ''}> <span>${escapeHtml(label)}</span> <span class="muted">(${escapeHtml(id)})</span></label>`;
    }).join('');

    colsWrap.innerHTML = Object.entries(ACCESS_TABLE_MAP)
      .map(([tabId, tableIds]) => {
        const first = tableIds[0];
        const headers = readTableHeaders(first);
        if (!headers.length) return '';
        const allowed = Array.isArray(accessEditorState.columnPermissions[tabId])
          ? new Set(accessEditorState.columnPermissions[tabId].map(normalizeAccessText))
          : null;
        const checks = headers
          .map((h) => {
            const on = !allowed || allowed.has(normalizeAccessText(h.label));
            return `<label style="display:inline-flex;align-items:center;gap:0.35rem;margin:0 0.55rem 0.4rem 0;"><input type="checkbox" class="usuarios-perm-col-check" data-tab-id="${escapeHtml(tabId)}" data-col-label="${escapeHtml(h.label)}" ${on ? 'checked' : ''}> ${escapeHtml(h.label)}</label>`;
          })
          .join('');
        return `<div class="card" style="padding:0.6rem;"><div style="font-weight:600;margin-bottom:0.35rem;">${escapeHtml(tabId)}</div><div>${checks}</div></div>`;
      })
      .filter(Boolean)
      .join('');
  }

  async function loadReportSchedules() {
    const tbody = qs('#tabla-report-schedules-body');
    if (!tbody) return;
    tbody.innerHTML = '<tr><td colspan="8" class="empty">Cargando…</td></tr>';
    try {
      const rows = await fetchJson(API + '/admin/report-schedules');
      const list = toArray(rows);
      reportSchedulesCache = list;
      if (!list.length) {
        tbody.innerHTML = '<tr><td colspan="8" class="empty">No hay programaciones configuradas.</td></tr>';
        return;
      }
      tbody.innerHTML = list
        .map((r) => {
          const dest = []
            .concat(Array.isArray(r.to) ? r.to : [])
            .concat(Array.isArray(r.cc) ? r.cc.map((x) => 'cc:' + x) : [])
            .filter(Boolean)
            .join(', ');
          const freq = r.frequency === 'weekly' ? ('Semanal (día ' + r.weekday + ')') : 'Diario';
          return (
            '<tr data-sched-id="' + escapeHtml(String(r.id || '')) + '">' +
            '<td>' + escapeHtml(String(r.id || '')) + '</td>' +
            '<td>' + escapeHtml(String(r.module || '')) + '</td>' +
            '<td>' + escapeHtml(freq) + '</td>' +
            '<td>' + escapeHtml(String(r.runAt || '')) + '</td>' +
            '<td>' + escapeHtml(dest || 'admins') + '</td>' +
            '<td class="muted">' + escapeHtml(String(r.lastSentAt || '—')) + '</td>' +
            '<td><input type="checkbox" class="usuarios-sched-enabled" data-sched-id="' + escapeHtml(String(r.id || '')) + '" ' + (r.enabled ? 'checked' : '') + '></td>' +
            '<td>' +
            '<button type="button" class="btn small outline usuarios-sched-edit" data-sched-id="' + escapeHtml(String(r.id || '')) + '" title="Editar"><i class="fas fa-edit"></i></button> ' +
            '<button type="button" class="btn small danger usuarios-sched-delete" data-sched-id="' + escapeHtml(String(r.id || '')) + '" title="Eliminar"><i class="fas fa-trash"></i></button>' +
            '</td>' +
            '</tr>'
          );
        })
        .join('');
    } catch (e) {
      reportSchedulesCache = [];
      tbody.innerHTML =
        '<tr><td colspan="8" class="empty">' + escapeHtml(parseApiError(e) || 'No se pudo cargar programaciones.') + '</td></tr>';
    }
  }

